133	// Permutes the rows of B for Turing and Ampere. Throws an error for other architectures.
134	// The data is permuted such that:
135	// For int8, each group of 16 rows is permuted using the map below:
136	//  0 1 8 9 2 3 10 11 4 5 12 13 6 7 14 15
137	// For int4, each group of 32 rows is permuted using the map below:
138	//  0 1 8 9 16 17 24 25 2 3 10 11 18 19 26 27 4 5 12 13 20 21 28 29 6 7 14 15 22 23 30 31
139	void permute_B_rows_for_mixed_gemm(int8_t*                    permuted_quantized_tensor,
140	                                   const int8_t*              quantized_tensor,
141	                                   const std::vector<size_t>& shape,
142	                                   QuantType                  quant_type,
143	                                   const int64_t              arch_version)
144	{
145	
146	    // We only want to run this step for weight only quant.
147	    FT_CHECK(quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY || quant_type == QuantType::INT8_WEIGHT_ONLY);
148	
149	    FT_CHECK_WITH_INFO(shape.size() == 2 || shape.size() == 3, "Shape must be 2-D or 3-D");
150	    const size_t num_experts = shape.size() == 2 ? 1 : shape[0];
151	    const size_t num_rows    = shape.size() == 2 ? shape[0] : shape[1];
152	    const size_t num_cols    = shape.size() == 2 ? shape[1] : shape[2];
153	
154	    const int BITS_PER_ELT  = get_bits_in_quant_type(quant_type);
155	    const int K             = 16 / BITS_PER_ELT;
156	    const int ELTS_PER_BYTE = 8 / BITS_PER_ELT;
157	    const int ELTS_PER_REG  = 32 / BITS_PER_ELT;
158	
159	    const uint32_t* input_byte_ptr  = reinterpret_cast<const uint32_t*>(quantized_tensor);
160	    uint32_t*       output_byte_ptr = reinterpret_cast<uint32_t*>(permuted_quantized_tensor);
161	
162	    int       MMA_SHAPE_N    = 8;
163	    int       B_ROWS_PER_MMA = 8 * K;
164	    const int elts_in_int32  = 32 / BITS_PER_ELT;
165	
166	    const int num_vec_cols = num_cols / elts_in_int32;
167	
168	    FT_CHECK_WITH_INFO(arch_version >= 75,
169	                       "Unsupported Arch. Pre-volta not supported. Column interleave not needed on Volta.");
170	
171	    FT_CHECK_WITH_INFO(
172	        num_rows % B_ROWS_PER_MMA == 0,
173	        fmtstr("Invalid shape for quantized tensor. Number of rows of quantized matrix must be a multiple of %d",
174	               B_ROWS_PER_MMA));
175	    FT_CHECK_WITH_INFO(
176	        num_cols % MMA_SHAPE_N == 0,
177	        fmtstr("Invalid shape for quantized tensor. On turing/Ampere, the number of cols must be a multiple of %d.",
178	               MMA_SHAPE_N));
179	
180	    // The code is written as below so it works for both int8 and packed int4.
181	    for (int expert = 0; expert < num_experts; ++expert) {
182	        const int64_t matrix_offset = expert * int64_t(num_rows) * int64_t(num_vec_cols);
183	        for (int base_row = 0; base_row < num_rows; base_row += B_ROWS_PER_MMA) {
184	            for (int tile_row = 0; tile_row < B_ROWS_PER_MMA; ++tile_row) {
185	
186	                for (int write_col = 0; write_col < num_vec_cols; ++write_col) {
187	                    const int write_row = base_row + tile_row;
188	                    const int tile_read_row =
189	                        8 * (((tile_row % ELTS_PER_REG) / 2)) + tile_row % 2 + 2 * (tile_row / ELTS_PER_REG);
190	                    const int read_row = base_row + tile_read_row;
191	                    const int read_col = write_col;
192	
193	                    const int64_t read_offset  = matrix_offset + int64_t(read_row) * num_vec_cols + read_col;
194	                    const int64_t write_offset = matrix_offset + int64_t(write_row) * num_vec_cols + write_col;
195	
196	                    output_byte_ptr[write_offset] = input_byte_ptr[read_offset];
197	                }
198	            }
199	        }
200	    }
201	}
202	
203	// We need to use this transpose to correctly handle packed int4 and int8 data
204	// The reason this code is relatively complex is that the "trivial" loops took a substantial
205	// amount of time to transpose leading to long preprocessing times. This seemed to be a big
206	// issue for relatively large models.
207	template<QuantType quant_type>
208	void subbyte_transpose_impl(int8_t*                    transposed_quantized_tensor,
209	                            const int8_t*              quantized_tensor,
210	                            const std::vector<size_t>& shape)
211	{
212	    const int bits_per_elt = get_bits_in_quant_type(quant_type);
213	
214	    FT_CHECK_WITH_INFO(shape.size() == 2 || shape.size() == 3, "Shape must be 2-D or 3-D");
215	    const size_t num_experts = shape.size() == 2 ? 1 : shape[0];
216	    const size_t num_rows    = shape.size() == 2 ? shape[0] : shape[1];
217	    const size_t num_cols    = shape.size() == 2 ? shape[1] : shape[2];
218	
219	    const size_t col_bytes       = num_cols * bits_per_elt / 8;
220	    const size_t col_bytes_trans = num_rows * bits_per_elt / 8;
221	    const size_t num_bytes       = size_t(num_experts) * num_rows * col_bytes;
222	
223	    const uint8_t* input_byte_ptr  = reinterpret_cast<const uint8_t*>(quantized_tensor);
224	    uint8_t*       output_byte_ptr = reinterpret_cast<uint8_t*>(transposed_quantized_tensor);
225	
226	    static_assert(quant_type == QuantType::INT8_WEIGHT_ONLY || quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY, "");
227	    static constexpr int ELTS_PER_BYTE = quant_type == QuantType::INT8_WEIGHT_ONLY ? 1 : 2;
228	
229	    static constexpr int M_TILE_L1 = 64;
230	    static constexpr int N_TILE_L1 = M_TILE_L1 / ELTS_PER_BYTE;
231	    uint8_t              cache_buf[M_TILE_L1][N_TILE_L1];
232	
233	    static constexpr int VECTOR_WIDTH = std::min(32, N_TILE_L1);
234	
235	    // We assume the dims are a multiple of vector width. Our kernels only handle dims which are multiples
236	    // of 64 for weight-only quantization. As a result, this seemed like a reasonable tradeoff because it
237	    // allows GCC to emit vector instructions.
238	    FT_CHECK_WITH_INFO(
239	        !(col_bytes_trans % VECTOR_WIDTH) && !(col_bytes % VECTOR_WIDTH),
240	        fmtstr(
241	            "Number of bytes for rows and cols must be a multiple of %d. However, num_rows_bytes = %ld and num_col_bytes = %d.",
242	            VECTOR_WIDTH,
243	            col_bytes_trans,
244	            col_bytes));
245	
246	    const int num_m_tiles = (num_rows + M_TILE_L1 - 1) / M_TILE_L1;
247	    const int num_n_tiles = (col_bytes + N_TILE_L1 - 1) / N_TILE_L1;
248	
249	    for (size_t expert = 0; expert < num_experts; ++expert) {
250	        const size_t matrix_offset = expert * num_rows * col_bytes;
251	        for (size_t row_tile_start = 0; row_tile_start < num_rows; row_tile_start += M_TILE_L1) {
252	            for (size_t col_tile_start_byte = 0; col_tile_start_byte < col_bytes; col_tile_start_byte += N_TILE_L1) {
253	
254	                const int row_limit = std::min(row_tile_start + M_TILE_L1, num_rows);
255	                const int col_limit = std::min(col_tile_start_byte + N_TILE_L1, col_bytes);
256	
257	                for (int ii = 0; ii < M_TILE_L1; ++ii) {
258	                    const int row = row_tile_start + ii;
259	
260	                    for (int jj = 0; jj < N_TILE_L1; jj += VECTOR_WIDTH) {
261	                        const int col = col_tile_start_byte + jj;
262	
263	                        const size_t logical_src_offset = matrix_offset + row * col_bytes + col;
264	
265	                        if (row < row_limit && col < col_limit) {
266	                            for (int v = 0; v < VECTOR_WIDTH; ++v) {
267	                                cache_buf[ii][jj + v] = input_byte_ptr[logical_src_offset + v];
268	                            }
269	                        }
270	                    }
271	                }
272	
273	                if (quant_type == QuantType::INT8_WEIGHT_ONLY) {
274	                    for (int ii = 0; ii < M_TILE_L1; ++ii) {
275	                        for (int jj = ii + 1; jj < N_TILE_L1; ++jj) {
276	                            std::swap(cache_buf[ii][jj], cache_buf[jj][ii]);
277	                        }
278	                    }
279	                }
280	                else if (quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY) {
281	
282	                    for (int ii = 0; ii < M_TILE_L1; ++ii) {
283	                        // Using M_TILE_L1 here is deliberate since we assume that the cache tile
284	                        // is square in the number of elements (not necessarily the number of bytes).
285	                        for (int jj = ii + 1; jj < M_TILE_L1; ++jj) {
286	                            const int ii_byte       = ii / ELTS_PER_BYTE;
287	                            const int ii_bit_offset = ii % ELTS_PER_BYTE;
288	
289	                            const int jj_byte       = jj / ELTS_PER_BYTE;
290	                            const int jj_bit_offset = jj % ELTS_PER_BYTE;
291	
292	                            uint8_t src_elt = 0xF & (cache_buf[ii][jj_byte] >> (4 * jj_bit_offset));
293	                            uint8_t tgt_elt = 0xF & (cache_buf[jj][ii_byte] >> (4 * ii_bit_offset));
294	
295	                            cache_buf[ii][jj_byte] &= (0xF0 >> (4 * jj_bit_offset));
296	                            cache_buf[jj][ii_byte] &= (0xF0 >> (4 * ii_bit_offset));
297	
298	                            cache_buf[ii][jj_byte] |= (tgt_elt << (4 * jj_bit_offset));
299	                            cache_buf[jj][ii_byte] |= (src_elt << (4 * ii_bit_offset));
300	                        }
301	                    }
302	                }
303	                else {
304	                    FT_CHECK_WITH_INFO(false, "Unsupported quantization type.");
305	                }
306	
307	                const size_t row_tile_start_trans      = col_tile_start_byte * ELTS_PER_BYTE;
308	                const size_t col_tile_start_byte_trans = row_tile_start / ELTS_PER_BYTE;
309	
310	                const int row_limit_trans = std::min(row_tile_start_trans + M_TILE_L1, num_cols);
311	                const int col_limit_trans = std::min(col_tile_start_byte_trans + N_TILE_L1, col_bytes_trans);
312	
313	                for (int ii = 0; ii < M_TILE_L1; ++ii) {
314	                    const int row = row_tile_start_trans + ii;
315	                    for (int jj = 0; jj < N_TILE_L1; jj += VECTOR_WIDTH) {
316	                        const int col = col_tile_start_byte_trans + jj;
317	
318	                        const size_t logical_tgt_offset = matrix_offset + row * col_bytes_trans + col;
319	
320	                        if (row < row_limit_trans && col < col_limit_trans) {
321	                            for (int v = 0; v < VECTOR_WIDTH; ++v) {
322	                                output_byte_ptr[logical_tgt_offset + v] = cache_buf[ii][jj + v];
323	                            }
324	                        }
325	                    }
326	                }
327	            }
328	        }
329	    }
330	}
331	
332	void subbyte_transpose(int8_t*                    transposed_quantized_tensor,
333	                       const int8_t*              quantized_tensor,
334	                       const std::vector<size_t>& shape,
335	                       QuantType                  quant_type)
336	{
337	
338	    if (quant_type == QuantType::INT8_WEIGHT_ONLY) {
339	        subbyte_transpose_impl<QuantType::INT8_WEIGHT_ONLY>(transposed_quantized_tensor, quantized_tensor, shape);
340	    }
341	    else if (quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY) {
342	        subbyte_transpose_impl<QuantType::PACKED_INT4_WEIGHT_ONLY>(
343	            transposed_quantized_tensor, quantized_tensor, shape);
344	    }
345	    else {
346	        FT_CHECK_WITH_INFO(false, "Invalid quant_tye");
347	    }
348	}
349	
350	void add_bias_and_interleave_int8s_inplace(int8_t* int8_tensor, const size_t num_elts)
351	{
352	    for (int ii = 0; ii < num_elts; ++ii) {
353	        int8_tensor[ii] = int8_t(int(int8_tensor[ii]) + 128);
354	    }
355	
356	    // Step 2 will transform the layout of a 32-bit register in CUDA in order to match the int4 layout. This has no
357	    // performance benefit and is purely so that int4 and int8 have the same layout.
358	    // Pictorially, this does the following:
359	    // bit 32                                                      0
360	    //      [elt_3  elt_2  elt_1  elt_0] (each elt occupies 8 bits)
361	    //
362	    // And it will rearrange the output 32 bit register to be the following:
363	    // bit 32                                                      0
364	    //      [elt_3  elt_1  elt_2  elt_0] (each elt occupies 8 bits)
365	
366	    FT_CHECK_WITH_INFO(num_elts % 4 == 0, "Dimensions of int8 tensor must be a multiple of 4 for register relayout");
367	    for (size_t base = 0; base < num_elts; base += 4) {
368	        std::swap(int8_tensor[base + 1], int8_tensor[base + 2]);
369	    }
370	}
371	
372	void add_bias_and_interleave_int4s_inplace(int8_t* packed_int4_tensor, const size_t num_elts)
373	{
374	    const int num_bytes = num_elts / 2;
375	
376	    // Step 1 will be to transform all the int4s to unsigned in order to make the dequantize take as little
377	    // instructions as possible in the CUDA code.
378	    for (size_t ii = 0; ii < num_bytes; ++ii) {
379	        int8_t transformed_packed_int4s = 0;
380	        int8_t transformed_first_elt =
381	            (int8_t(packed_int4_tensor[ii] << 4) >> 4) + 8;  // The double shift here is to ensure sign extension
382	        int8_t transformed_second_elt = (packed_int4_tensor[ii] >> 4) + 8;
383	
384	        FT_CHECK_WITH_INFO(transformed_first_elt >= 0 && transformed_first_elt <= 15,
385	                           "Illegal result for int4 transform (first elt)");
386	        FT_CHECK_WITH_INFO(transformed_second_elt >= 0 && transformed_second_elt <= 15,
387	                           "Illegal result for int4 transform (second elt)");
388	
389	        // We don't need to mask in these ops since everything should be in the range 0-15
390	        transformed_packed_int4s |= transformed_first_elt;
391	        transformed_packed_int4s |= (transformed_second_elt << 4);
392	        packed_int4_tensor[ii] = transformed_packed_int4s;
393	    }
394	
395	    // Step 2 will transform the layout of a 32-bit register in CUDA in order to minimize the number of shift & logical
396	    // instructions That are needed to extract the int4s in the GEMM main loop. Pictorially, the loop below will do the
397	    // following: Take as input a 32 bit register with layout: bit 32 0
398	    //      [elt_7  elt_6  elt_5  elt_4  elt_3  elt_2  elt_1  elt_0] (each elt occupies 4 bits)
399	    //
400	    // And it will rearrange the output 32 bit register to be the following:
401	    // bit 32                                                      0
402	    //      [elt_7  elt_5  elt_3  elt_1  elt_6  elt_4  elt_2  elt_0] (each elt occupies 4 bits)
403	
404	    FT_CHECK_WITH_INFO(num_bytes % 4 == 0, "Dimensions of int4 tensor must be a multiple of 8 for register relayout");
405	    const size_t num_registers = num_bytes / 4;
406	
407	    uint32_t* register_ptr = reinterpret_cast<uint32_t*>(packed_int4_tensor);
408	    for (size_t ii = 0; ii < num_registers; ++ii) {
409	        const uint32_t current_register     = register_ptr[ii];
410	        uint32_t       transformed_register = 0;
411	
412	        for (int dest_idx = 0; dest_idx < 8; ++dest_idx) {
413	            const int src_idx    = dest_idx < 4 ? 2 * dest_idx : 2 * (dest_idx - 4) + 1;
414	            const int src_shift  = 4 * src_idx;
415	            const int dest_shift = 4 * dest_idx;
416	
417	            const uint32_t src_bits = (current_register >> src_shift) & 0xF;
418	            transformed_register |= (src_bits << dest_shift);
419	        }
420	        register_ptr[ii] = transformed_register;
421	    }
422	}
423	
424	void add_bias_and_interleave_quantized_tensor_inplace(int8_t* tensor, const size_t num_elts, QuantType quant_type)
425	{
426	    if (quant_type == QuantType::INT8_WEIGHT_ONLY) {
427	        add_bias_and_interleave_int8s_inplace(tensor, num_elts);
428	    }
429	    else if (quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY) {
430	        add_bias_and_interleave_int4s_inplace(tensor, num_elts);
431	    }
432	    else {
433	        FT_CHECK_WITH_INFO(false, "Invalid quantization type for interleaving.");
434	    }
435	}
436	
437	void interleave_column_major_tensor(int8_t*                    interleaved_quantized_tensor,
438	                                    const int8_t*              quantized_tensor,
439	                                    const std::vector<size_t>& shape,
440	                                    QuantType                  quant_type,
441	                                    LayoutDetails              details)
442	{
443	
444	    // We only want to run this step for weight only quant.
445	    FT_CHECK(quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY || quant_type == QuantType::INT8_WEIGHT_ONLY);
446	
447	    FT_CHECK_WITH_INFO(shape.size() == 2 || shape.size() == 3, "Shape must be 2-D or 3-D");
448	    const size_t num_experts = shape.size() == 2 ? 1 : shape[0];
449	    const size_t num_rows    = shape.size() == 2 ? shape[0] : shape[1];
450	    const size_t num_cols    = shape.size() == 2 ? shape[1] : shape[2];
451	
452	    const int BITS_PER_ELT  = get_bits_in_quant_type(quant_type);
453	    const int elts_in_int32 = 32 / BITS_PER_ELT;
454	
455	    const int rows_per_tile = details.rows_per_column_tile;
456	
457	    FT_CHECK_WITH_INFO(
458	        !(num_rows % elts_in_int32),
459	        fmtstr("The number of rows must be a multiple of %d but the number of rows is %d.", elts_in_int32, num_rows));
460	
461	    FT_CHECK_WITH_INFO(!(num_cols % rows_per_tile),
462	                       fmtstr("The number of columns must be a multiple of %d but the number of columns is %ld",
463	                              rows_per_tile,
464	                              num_cols));
465	
466	    const uint32_t* input_byte_ptr  = reinterpret_cast<const uint32_t*>(quantized_tensor);
467	    uint32_t*       output_byte_ptr = reinterpret_cast<uint32_t*>(interleaved_quantized_tensor);
468	
469	    FT_CHECK_WITH_INFO(!(num_cols % rows_per_tile),
470	                       fmtstr("The number of columns must be a multiple of %d but the number of columns is %d.",
471	                              rows_per_tile,
472	                              num_cols));
473	
474	    const int num_vec_rows      = num_rows / elts_in_int32;
475	    const int vec_rows_per_tile = rows_per_tile / elts_in_int32;
476	    const int interleave        = details.columns_interleaved;
477	
478	    for (int expert = 0; expert < num_experts; ++expert) {
479	        const int64_t matrix_offset = expert * int64_t(num_vec_rows) * int64_t(num_cols);
480	        for (int read_col = 0; read_col < num_cols; ++read_col) {
481	            const int64_t write_col = read_col / interleave;
482	            for (int base_vec_row = 0; base_vec_row < num_vec_rows; base_vec_row += vec_rows_per_tile) {
483	                for (int vec_read_row = base_vec_row;
484	                     vec_read_row < std::min(num_vec_rows, base_vec_row + vec_rows_per_tile);
485	                     ++vec_read_row) {
486	                    const int64_t vec_write_row = interleave * base_vec_row
487	                                                  + vec_rows_per_tile * (read_col % interleave)
488	                                                  + vec_read_row % vec_rows_per_tile;
489	
490	                    const int64_t read_offset = matrix_offset + int64_t(read_col) * num_vec_rows + vec_read_row;
491	                    const int64_t write_offset =
492	                        matrix_offset + int64_t(write_col) * num_vec_rows * interleave + vec_write_row;
493	                    output_byte_ptr[write_offset] = input_byte_ptr[read_offset];
494	                }
495	            }
496	        }
497	    }
498	}
499	
500	void preprocess_weights_for_mixed_gemm(int8_t*                    preprocessed_quantized_weight,
501	                                       const int8_t*              row_major_quantized_weight,
502	                                       const std::vector<size_t>& shape,
503	                                       QuantType                  quant_type)
504	{
505	    LayoutDetails details = getLayoutDetailsForTransform(quant_type);
506	
507	    FT_CHECK_WITH_INFO(shape.size() == 2 || shape.size() == 3, "Shape must be 2-D or 3-D");
508	
509	    size_t num_elts = 1;
510	    for (const auto& dim : shape) {
511	        num_elts *= dim;
512	    }
513	
514	    const size_t num_bytes = num_elts * get_bits_in_quant_type(quant_type) / 8;
515	
516	    std::vector<int8_t> src_buf(num_bytes);
517	    std::vector<int8_t> dst_buf(num_bytes);
518	    std::copy(row_major_quantized_weight, row_major_quantized_weight + num_bytes, src_buf.begin());
519	
520	    // Works on row major data, so issue this permutation first.
521	    if (details.uses_imma_ldsm) {
522	        const int arch = fastertransformer::getSMVersion();
523	        permute_B_rows_for_mixed_gemm(dst_buf.data(), src_buf.data(), shape, quant_type, arch);
524	        src_buf.swap(dst_buf);
525	    }
526	
527	    if (details.layoutB == LayoutDetails::Layout::COLUMN_MAJOR) {
528	        subbyte_transpose(dst_buf.data(), src_buf.data(), shape, quant_type);
529	        src_buf.swap(dst_buf);
530	    }
531	
532	    if (details.columns_interleaved > 1) {
533	        interleave_column_major_tensor(dst_buf.data(), src_buf.data(), shape, quant_type, details);
534	        src_buf.swap(dst_buf);
535	    }
536	
537	    add_bias_and_interleave_quantized_tensor_inplace(src_buf.data(), num_elts, quant_type);
538	    std::copy(src_buf.begin(), src_buf.end(), preprocessed_quantized_weight);
539	}
540	
541	/*
542	    Arguments:
543	      input_weight_ptr - the weight tensor to be quantized. Must be 2-D or 3-D and of type FP16.
544	
545	      quant_type - the type of the output quantization weight.
546	
547	    This function does symmetric quantization on 2-D or 3-D tensors. It uses the full int range and assumes the
548	    zero-point is zero and will automatically construct the scales.
549	
550	    It always quantizes the last axis of the tensor. For 3-D tensors, it operates in "batched" mode where the tensor is
551	    viewed as a stack of matrices and a scale is produced for each column of every matrix.
552	
553	Outputs
554	    processed_quantized_weight - quantized AND processed weight for GEMM. This MUST be used with the CUTLASS GEMM
555	    unprocessed_quantized_weight - quantized but unprocessed weights. Useful for reference checking.
556	    scale_ptr - scales for the quantized weight.
557	
558	    Note that the returned quantized_weights will be preprocessed in a way to accelerate the mixed type GEMM. The data
559	    layout may not make sense if printed.
560	
561	    Shapes:
562	      quant_type == int8:
563	        If weight is a [m,n] matrix, quantized_weights will have shape [m,n] and scales of shape [n]
564	        If weight is a [b,m,n] tensor, unprocessed_quantized_weight will have shape [b,m,n] and scales of shape [b,n]
565	      quant_type == int4:
566	        If weight is a [m,n] matrix, quantized_weights will have shape [m, ceil(n/2)] and scales of shape [n]
567	        If weight is a [b,m,n] tensor, unprocessed_quantized_weight will have shape [b,m, ceil(n/2)] and scales of shape
568	          [b,n]
569	
570	      The quantized_weight will be of type torch.int8 and have two int4 values packed in a single byte. This is the
571	      reason for halving the shape. At the time of writing this code, there was not an elegant way to handle this kind
572	      of batched quantization using torch's quantized tensors (to the best of the author's knowledge). Scale tensors
573	      must have a dimension of 1, which breaks the semantics we need for batched weights.
574	  */
575	
576	template<typename ComputeType, typename WeightType>
577	void symmetric_quantize(int8_t*                    processed_quantized_weight,
578	                        int8_t*                    unprocessed_quantized_weight,
579	                        ComputeType*               scale_ptr,
580	                        const WeightType*          input_weight_ptr,
581	                        const std::vector<size_t>& shape,
582	                        QuantType                  quant_type)
583	{
584	
585	    FT_CHECK_WITH_INFO(processed_quantized_weight, "Processed quantized tensor is NULL");
586	    FT_CHECK_WITH_INFO(scale_ptr, "Scale output pointer is NULL");
587	    FT_CHECK_WITH_INFO(input_weight_ptr, "Input weight pointer is NULL");
588	
589	    FT_CHECK_WITH_INFO(shape.size() == 2 || shape.size() == 3, "Shape must be 2-D or 3-D");
590	    const size_t num_experts = shape.size() == 2 ? 1 : shape[0];
591	    const size_t num_rows    = shape.size() == 2 ? shape[0] : shape[1];
592	    const size_t num_cols    = shape.size() == 2 ? shape[1] : shape[2];
593	
594	    const int bits_in_type      = get_bits_in_quant_type(quant_type);
595	    const int bytes_per_out_col = num_cols * bits_in_type / 8;
596	
597	    std::vector<int8_t> weight_buf;
598	    if (unprocessed_quantized_weight == nullptr) {
599	        weight_buf.resize(num_experts * num_rows * num_cols);
600	        unprocessed_quantized_weight = weight_buf.data();
601	    }
602	
603	    const int   input_mat_size     = num_rows * num_cols;
604	    const int   quantized_mat_size = num_rows * bytes_per_out_col;
605	    const float quant_range_scale  = 1.f / float(1 << (bits_in_type - 1));
606	
607	    std::vector<float> per_col_max(num_cols);
608	
609	    for (int expert = 0; expert < num_experts; ++expert) {
610	        const WeightType* current_weight           = input_weight_ptr + expert * input_mat_size;
611	        int8_t*           current_quantized_weight = unprocessed_quantized_weight + expert * quantized_mat_size;
612	
613	        // First we find the per column max for this expert weight.
614	        for (int jj = 0; jj < num_cols; ++jj) {
615	            per_col_max[jj] = 0.f;
616	        }
617	
618	        for (int ii = 0; ii < num_rows; ++ii) {
619	            const WeightType* current_weight_row = current_weight + ii * num_cols;
620	            for (int jj = 0; jj < num_cols; ++jj) {
621	                per_col_max[jj] = std::max(per_col_max[jj], std::abs(float(current_weight_row[jj])));
622	            }
623	        }
624	
625	        // Then, we construct the scales
626	        ComputeType* current_scales = scale_ptr + expert * num_cols;
627	        for (int jj = 0; jj < num_cols; ++jj) {
628	            per_col_max[jj] *= quant_range_scale;
629	            current_scales[jj] = ComputeType(per_col_max[jj]);
630	        }
631	
632	        // Finally, construct the weights.
633	        for (int ii = 0; ii < num_rows; ++ii) {
634	            int8_t*           current_quantized_weight_row = current_quantized_weight + ii * bytes_per_out_col;
635	            const WeightType* current_weight_row           = current_weight + ii * num_cols;
636	            for (int jj = 0; jj < bytes_per_out_col; ++jj) {
637	
638	                if (quant_type == QuantType::INT8_WEIGHT_ONLY) {
639	                    const float  col_scale           = per_col_max[jj];
640	                    const float  weight_elt          = float(current_weight_row[jj]);
641	                    const float  scaled_weight       = round(weight_elt / col_scale);
642	                    const int8_t clipped_weight      = int8_t(std::max(-128.f, std::min(127.f, scaled_weight)));
643	                    current_quantized_weight_row[jj] = clipped_weight;
644	                }
645	                else if (quant_type == QuantType::PACKED_INT4_WEIGHT_ONLY) {
646	
647	                    // We will pack two int4 elements per iteration of the inner loop.
648	                    int8_t packed_int4s = 0;
649	                    for (int packed_idx = 0; packed_idx < 2; ++packed_idx) {
650	                        const int input_idx = 2 * jj + packed_idx;
651	                        if (input_idx < num_cols) {
652	                            const float  col_scale      = per_col_max[input_idx];
653	                            const float  weight_elt     = float(current_weight_row[input_idx]);
654	                            const float  scaled_weight  = round(weight_elt / col_scale);
655	                            int          int_weight     = int(scaled_weight);
656	                            const int8_t clipped_weight = std::max(-8, std::min(7, int_weight));
657	
658	                            // Kill the sign extension bits (hence 0x0F mask) then shift to upper bits
659	                            // if packing the second int4 and or the bits into the final result.
660	                            packed_int4s |= ((clipped_weight & 0x0F) << (4 * packed_idx));
661	                        }
662	                    }
663	                    current_quantized_weight_row[jj] = packed_int4s;
664	                }
665	                else {
666	                    FT_CHECK_WITH_INFO(false, "Unsupported quantization type");
667	                }
668	            }
669	        }
670	    }
671	
672	    preprocess_weights_for_mixed_gemm(processed_quantized_weight, unprocessed_quantized_weight, shape, quant_type);
673	}
674	
675	template void
676	symmetric_quantize<half, float>(int8_t*, int8_t*, half*, const float*, const std::vector<size_t>&, QuantType);
677	
678	template void
679	symmetric_quantize<half, half>(int8_t*, int8_t*, half*, const half*, const std::vector<size_t>&, QuantType);
680	
681	#ifdef ENABLE_BF16
682	template void symmetric_quantize<__nv_bfloat16, __nv_bfloat16>(
683	    int8_t*, int8_t*, __nv_bfloat16*, const __nv_bfloat16*, const std::vector<size_t>&, QuantType);
684	
685	template void symmetric_quantize<__nv_bfloat16, float>(
686	    int8_t*, int8_t*, __nv_bfloat16*, const float*, const std::vector<size_t>&, QuantType);
687	#endif
688	
689	template<typename ComputeType, typename WeightType>
690	void symmetric_quantize(int8_t*                    processed_quantized_weight,
691	                        ComputeType*               scale_ptr,
692	                        const WeightType*          input_weight_ptr,
693	                        const std::vector<size_t>& shape,
694	                        QuantType                  quant_type)
695	{
696	    symmetric_quantize(processed_quantized_weight, nullptr, scale_ptr, input_weight_ptr, shape, quant_type);
697	}
698	
699	template void symmetric_quantize<float, float>(int8_t*, float*, const float*, const std::vector<size_t>&, QuantType);
700	
701	template void symmetric_quantize<half, float>(int8_t*, half*, const float*, const std::vector<size_t>&, QuantType);
702	
703	template void symmetric_quantize<half, half>(int8_t*, half*, const half*, const std::vector<size_t>&, QuantType);
704	
705	#ifdef ENABLE_BF16
706	template void symmetric_quantize<__nv_bfloat16, __nv_bfloat16>(
707	    int8_t*, __nv_bfloat16*, const __nv_bfloat16*, const std::vector<size_t>&, QuantType);
708	
709	template void
710	symmetric_quantize<__nv_bfloat16, half>(int8_t*, __nv_bfloat16*, const half*, const std::vector<size_t>&, QuantType);
711	
712	template void
713	symmetric_quantize<half, __nv_bfloat16>(int8_t*, half*, const __nv_bfloat16*, const std::vector<size_t>&, QuantType);
714	
715	template void
716	symmetric_quantize<__nv_bfloat16, float>(int8_t*, __nv_bfloat16*, const float*, const std::vector<size_t>&, QuantType);
717	#endif
718	
719	}  // namespace fastertransformer

