56	Tensor permute_B_rows_for_mixed_gemm(Tensor quantized_tensor, torch::ScalarType quant_type, const int64_t arch_version)
57	{
58	    auto _st = quantized_tensor.scalar_type();
59	    CHECK_CPU(quantized_tensor);
